    internal class ResponseErrorConverter : JsonConverter<ResponseError>
    {
        public override ResponseError Read(ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options)
        {
            using var doc = JsonDocument.ParseValue(ref reader);
            var element = doc.RootElement;
            string code = null;
            string message = null;
            if (element.TryGetProperty("code", out var codeProp))
                code = codeProp.GetString();
            if (element.TryGetProperty("message", out var msgProp))
                message = msgProp.GetString();
            return new ResponseError(code, message);
        }

        public override void Write(Utf8JsonWriter writer, ResponseError value, JsonSerializerOptions options)
        {
            writer.WriteStartObject();
            if (value.Code != null)
            {
                writer.WriteString("code"u8, value.Code);
            }
            if (value.Message != null)
            {
                writer.WriteString("message"u8, value.Message);
            }
            if (value.Target != null)
            {
                writer.WriteString("target"u8, value.Target);
            }
            if (value.Details is { Count: > 0 })
            {
                writer.WriteStartArray("details"u8);
                foreach (var detail in value.Details)
                {
                    Write(writer, detail, options);
                }
                writer.WriteEndArray();
            }
            writer.WriteEndObject();
        }
    }

